game_info.concept:
{
  "game_name": "Solitaire by MobilityWare",
  "genre": "Casino",
  "core_mechanics": {
    "player_actions": [
      {
        "action": "Select/Pick Up Card",
        "trigger": "Mouse click on a face-up card in a tableau column, or on the top card of the waste pile, or on a card stack (to move multiple valid cards). Double click to auto-move to foundation.",
        "details": "Clicking a card picks it up, allowing it to be dragged. Double-clicking a valid card automatically moves it to its corresponding foundation pile if possible."
      },
      {
        "action": "Move Card",
        "trigger": "Mouse drag from a picked-up card to a valid target pile/column.",
        "details": "Dragging a card (or stack) and releasing it over a valid destination (tableau column, foundation pile) will attempt the move. Invalid drops will snap the card back to its original position."
      },
      {
        "action": "Draw from Stock",
        "trigger": "Mouse click on the stock pile.",
        "details": "Moves 1 or 3 cards (depending on current game mode) from the stock pile to the waste pile. If stock is empty, clicking allows cycling the waste pile back to the stock."
      },
      {
        "action": "Undo Last Move",
        "trigger": "UI button click.",
        "details": "Reverts the game state to the previous valid move. Unlimited undo is available."
      },
      {
        "action": "Toggle Draw Mode",
        "trigger": "UI button click.",
        "details": "Switches between 'Draw 1' and 'Draw 3' card modes from the stock pile."
      },
      {
        "action": "Auto Complete",
        "trigger": "UI button click.",
        "details": "Once all tableau cards are face-up, this action automatically moves all remaining cards to their foundation piles to complete the game."
      }
    ],
    "gameplay_rules_systems": [
      "Standard Klondike Solitaire rules: Build tableau columns down by alternating colors (e.g., Red Queen on Black King). Build foundation piles up by suit from Ace to King.",
      "Tableau setup: Seven columns; leftmost has one card, rightmost has seven. Top card of each column is face-up, others face-down.",
      "Stock/Waste pile: Cards dealt from stock to waste. Waste pile cards can be moved to tableau or foundation.",
      "Card visibility: Only top card of tableau column is interactable. When a face-up card is moved from a tableau column, the card beneath it (if any) is flipped face-up.",
      "Valid moves: Cards can only be placed on a card of the next higher rank and opposite color in a tableau column. Only a King or a stack starting with a King can be placed on an empty tableau column. Cards can only be placed on a foundation pile if it's the next higher rank of the same suit, starting with an Ace.",
      "Unlimited Undo: A history of game states is maintained to allow infinite backtracking.",
      "Draw 1/Draw 3: Player selects how many cards are drawn from the stock at a time."
    ],
    "state_tracking": [
      "Deck state: Remaining cards in stock.",
      "Waste pile: Cards currently in the waste pile.",
      "Tableau columns: Cards in each of the 7 columns, including their face-up/face-down status and order.",
      "Foundation piles: Cards in each of the 4 foundation piles.",
      "Current score.",
      "Total moves made.",
      "Time elapsed since game start.",
      "Undo history stack (for game states).",
      "Current 'Draw 1' or 'Draw 3' mode setting.",
      "Game state (playing, paused, won, lost).",
      "Current level progression."
    ]
  },
  "visual_elements": {
    "game_objects": [
      "Cards (front and back)",
      "Tableau Column outlines/slots (7)",
      "Foundation Pile outlines/slots (4)",
      "Stock Pile outline/slot",
      "Waste Pile outline/slot",
      "UI Buttons (Undo, Draw Mode Toggle, Auto Complete, Pause)",
      "Score Display",
      "Time Display",
      "Moves Display",
      "Level Indicator",
      "Winning/Losing message areas"
    ],
    "visual_representations": [
      "Cards: Rectangular shapes. Fronts depict suit (Spades, Hearts, Diamonds, Clubs) and rank (A, 2-10, J, Q, K). Standard playing card imagery or simplified p5.js drawing (e.g., text for rank/suit). Backs are uniform, generic pattern. Dimensions: ~70px width, ~96px height.",
      "Piles/Slots: Lightly dashed or solid rectangular outlines (e.g., light gray, 70x96px) to indicate clickable/droppable areas. When empty, they show a placeholder.",
      "Background: A solid color (e.g., deep green or blue) or simple gradient/texture to mimic a card table.",
      "UI Elements: Rectangular buttons with descriptive text (e.g., 'Undo', 'Draw 1/3', 'Auto Complete', 'Pause'). Colors to contrast with the background (e.g., light gray buttons with black text).",
      "Text Displays: Score, Time, Moves, Level shown as legible text in contrasting colors (e.g., white or yellow) against the background.",
      "Game Over/Win Screens: Centered text messages ('YOU WIN!', 'NO MORE MOVES') with options to restart or return to menu."
    ],
    "animations_visual_effects": [
      "Card Dragging: When picked up, a card (or stack) will slightly lift and follow the mouse cursor with smooth translation.",
      "Card Dropping: When a card is dropped on a valid pile, it smoothly slides into place. On invalid drops, it quickly snaps back to its origin.",
      "Card Flipping: When a face-down tableau card is revealed, it could have a quick rotation or fade effect to transition to its face-up state.",
      "Auto-Move to Foundation: Cards rapidly and sequentially slide from tableau/waste to their respective foundation piles.",
      "Win Animation: A cascade or 'fan' of cards flying into the foundation piles from off-screen or from remaining tableau/waste, culminating in a celebratory message."
    ]
  },
  "control_scheme": {
    "ArrowLeft": "Selects the next pile/column to the left (cycling through tableau, waste, stock, foundations).",
    "ArrowRight": "Selects the next pile/column to the right (cycling through tableau, waste, stock, foundations).",
    "ArrowUp": "If a pile/column is selected, moves the card selection cursor up within that pile (e.g., selecting the card above).",
    "ArrowDown": "If a pile/column is selected, moves the card selection cursor down within that pile (e.g., selecting the card below or the top-most face-down card to reveal).",
    "Space": "Acts as a primary action key: if a card is selected, it's 'picked up'. If a card is picked up, pressing space again attempts to drop it to the currently indicated valid drop zone (if any, cycling through valid zones if multiple exist). If stock is selected, draws card(s). If no card selected, acts as 'double-tap' for auto-move if a valid auto-move card exists.",
    "Shift": "Toggles the 'Draw 1' / 'Draw 3' mode.",
    "Z": "Performs an 'Undo' action, reverting the last move.",
    "W": "Draws card(s) from the Stock pile to the Waste pile. If the stock is empty, it cycles the waste back to stock.",
    "A": "Initiates 'Auto Complete' functionality if all tableau cards are face-up.",
    "S": "If a card is currently 'picked up' or selected, attempts to auto-move it to a valid foundation pile."
  },
  "game_states": {
    "LOADING": {
      "description": "Initial state where game assets (images, sounds) are loaded.",
      "triggers": "Game launch.",
      "transitions": "Upon successful asset load -> MAIN_MENU."
    },
    "MAIN_MENU": {
      "description": "Player sees options like 'New Game', 'Options' (Simplified for Draw 1/3), 'How to Play'.",
      "triggers": "From LOADING after load, from PAUSED, GAME_OVER, GAME_WON after relevant options selected.",
      "transitions": "'New Game' -> PLAYING (for current level), 'Options' -> OPTIONS, 'How to Play' -> HOW_TO_PLAY (static display)."
    },
    "OPTIONS": {
      "description": "Player can toggle 'Draw 1' / 'Draw 3' mode.",
      "triggers": "From MAIN_MENU.",
      "transitions": "Back button -> MAIN_MENU."
    },
    "HOW_TO_PLAY": {
      "description": "Displays basic Solitaire rules and controls.",
      "triggers": "From MAIN_MENU.",
      "transitions": "Back button -> MAIN_MENU."
    },
    "PLAYING": {
      "description": "The main game loop where player interacts with cards.",
      "triggers": "From MAIN_MENU (New Game), from PAUSED (Resume).",
      "transitions": "Player action (e.g., clicking Pause) -> PAUSED. Game completed successfully -> GAME_WON. No more valid moves -> GAME_OVER."
    },
    "PAUSED": {
      "description": "Game is suspended. A pause menu overlay is displayed with 'Resume', 'Restart Game', 'Main Menu' options.",
      "triggers": "Player presses 'Pause' (e.g., Esc key - not in specified list, so let's say 'P' key), or clicks a 'Pause' UI button during PLAYING.",
      "transitions": "'Resume' -> PLAYING. 'Restart Game' -> PLAYING (new game for current level). 'Main Menu' -> MAIN_MENU."
    },
    "GAME_WON": {
      "description": "All cards successfully moved to foundation piles. Displays score, time, moves, and a 'Win!' message. Awards 'crowns' for level progression.",
      "triggers": "All 52 cards are in the foundation piles.",
      "transitions": "'Next Level' (if available and criteria met) -> LEVEL_TRANSITION. 'Restart Game' -> PLAYING (new game for current level). 'Main Menu' -> MAIN_MENU."
    },
    "GAME_OVER": {
      "description": "No more valid moves can be made, and not all cards are in foundations. Displays score, time, moves, and 'No More Moves' message.",
      "triggers": "No valid moves are possible on the board.",
      "transitions": "'Restart Game' -> PLAYING (new game for current level). 'Main Menu' -> MAIN_MENU."
    },
    "LEVEL_TRANSITION": {
      "description": "Brief interstitial screen displaying 'Level X Complete! Starting Level Y...'",
      "triggers": "Player completes the winning conditions for the current level (e.g., X wins) and chooses to advance.",
      "transitions": "After a short delay (e.g., 2 seconds) -> PLAYING (with new level settings)."
    }
  },
  "win_conditions": "The player wins the game when all 52 cards, sorted by suit from Ace to King, are successfully moved into the four foundation piles. This typically involves uncovering all face-down cards in the tableau and strategically moving cards.",
  "lose_conditions": "The player loses the game when no further valid moves can be made from the stock, waste, or tableau columns, and the game has not been won. This state is reached when the player is 'stuck' and cannot advance any cards to the foundations or reveal new cards.",
  "scoring_system": {
    "points_actions": [
      {
        "action": "Move card from Waste pile to Tableau column",
        "points": "+5"
      },
      {
        "action": "Move card from Waste pile to Foundation pile",
        "points": "+10"
      },
      {
        "action": "Move card from Tableau column to Foundation pile",
        "points": "+10"
      },
      {
        "action": "Flip a face-down Tableau card face-up",
        "points": "+5"
      },
      {
        "action": "Move card from Foundation pile back to Tableau (penalty for undoing a foundation move)",
        "points": "-15"
      },
      {
        "action": "Using 'Undo' functionality",
        "points": "-5"
      },
      {
        "action": "Completing a game (Win bonus)",
        "points": "+1000"
      }
    ],
    "bonus_multipliers": [
      "Speed Bonus: (20000 / seconds_taken) - Points added to final score, capped at a maximum of 5000 points. This encourages faster play.",
      "No Undo Bonus: If a game is completed without using 'Undo', an additional +500 points."
    ],
    "high_score_system": "Yes. A local high score system will be implemented using browser's `localStorage` to save the top 10 scores, associated with the player's name (if entered, otherwise anonymous). Scores are updated upon game completion (win or lose, though only wins typically make the high score list).",
    "score_display": "The current player's score will be displayed prominently in the top-left corner of the game screen, formatted as 'SCORE: [value]'.",
    "score_affect_gameplay": "The score does not directly affect gameplay mechanics. It serves as a metric for player performance, progression, and local competition. Higher scores contribute to level progression and unlock new levels indirectly by demonstrating mastery (especially in later levels)."
  },
  "level_system": {
    "levels": [
      {
        "level_number": 1,
        "name": "Novice Hand",
        "difficulty_progression": "Fixed, easier starting deal (fewer face-down cards, more immediate valid moves, less 'buried' key cards). Only 'Draw 1' card mode available from the stock. No time limit.",
        "advance_condition": "Successfully complete one game (win) with a score of at least 1500 points.",
        "transition_display": "Upon winning: 'Level 1 Complete! Score: [X]. Unlocking Level 2...' then 'Starting Level 2...'."
      },
      {
        "level_number": 2,
        "name": "Standard Play",
        "difficulty_progression": "Randomized deals (standard Klondike shuffling). Player can now choose between 'Draw 1' or 'Draw 3' card mode. No time limit. Introduces more complex card placements.",
        "advance_condition": "Successfully complete two games (win) in this level, with an average score of at least 2000 points per game.",
        "transition_display": "Upon winning the second game: 'Level 2 Complete! Average Score: [X]. Unlocking Level 3...' then 'Starting Level 3...'."
      },
      {
        "level_number": 3,
        "name": "Expert Challenge",
        "difficulty_progression": "Only 'Draw 3' card mode is available from the stock (forced). Deals are algorithmically generated to be solvable but more challenging (e.g., specific key cards are buried deeper, longer sequences needed for tableau manipulation). A soft time limit for score bonus (but no loss).",
        "advance_condition": "Successfully complete three games (win) in this level within a cumulative total of 30 minutes, with an average score of at least 2500 points per game.",
        "transition_display": "Upon winning the third game: 'Level 3 Complete! Total Time: [X]. Unlocking Level 4...' then 'Starting Level 4...'."
      },
      {
        "level_number": 4,
        "name": "Master Solitaire",
        "difficulty_progression": "Only 'Draw 3' card mode. Deals are pre-defined 'hard' solvable deals, requiring careful planning. A strict time limit for completion (e.g., 10 minutes per game). Failure to complete within time results in a game loss.",
        "advance_condition": "Successfully complete two games (win) in this level within the 10-minute time limit for each game, achieving a high score of at least 3000 points per game.",
        "transition_display": "Upon winning the second game: 'Level 4 Complete! Mastered Timed Play. Unlocking Level 5...' then 'Starting Level 5...'."
      },
      {
        "level_number": 5,
        "name": "Grand Master",
        "difficulty_progression": "Only 'Draw 3' card mode. More difficult pre-defined deals with fewer immediately obvious moves. Shorter strict time limit (e.g., 7 minutes per game). Focus is on maximizing score through efficient moves and speed.",
        "advance_condition": "Successfully complete three games (win) in this level within the 7-minute time limit for each game, achieving an average score of at least 3500 points per game.",
        "transition_display": "Upon winning the third game: 'Congratulations! You are a Grand Master! Final Score: [X]'. This is the final progression level."
      }
    ],
    "player_advancement": "The player advances to the next level only after successfully meeting the specific win conditions and score/time requirements for the current level. Progress is saved via `localStorage`.",
    "level_transition_display": "Between levels, a full-screen overlay will appear for a few seconds stating 'LEVEL [X] COMPLETE!' and 'STARTING LEVEL [Y]...' before loading the next level's game state.",
    "level_indicator": "The current level number will be displayed on screen, typically in the bottom-left corner, formatted as 'LEVEL: [value]'."
  },
  "simplifications": {
    "multiplayer_features": "The 'Multiplayer Solitaire' mode is entirely removed. The game will be a single-player experience.",
    "daily_challenges_achievements": "Simplified. 'Daily Challenges' and 'Monthly Trophies' are abstracted into the core level progression system and internal 'crowns' counter upon winning. Achievements are tracked locally (e.g., 'X games won', 'Y cards moved to foundation') but won't have a dedicated external interface beyond simple in-game notifications if implemented.",
    "global_leaderboards": "Replaced with a local high score system, stored in `localStorage`.",
    "card_art_animations": "While card fronts will distinguish suit/rank, complex detailed card art and advanced 3D-like animations are simplified to basic 2D p5.js drawing techniques (rectangles, text, basic image sprites if available) and smooth 2D translations/rotations.",
    "settings_options": "Limited to core gameplay options like 'Draw 1' / 'Draw 3' toggle.",
    "game_engine_choice": "Matter.js (physics engine) is deemed unnecessary as card movements are discrete and rule-based, not physics-driven. p5.js will handle all rendering and game logic."
  },
  "implementation_notes": "All scores will be displayed in the top-left corner as 'SCORE: [value]'. The current level will be displayed in the bottom-left corner as 'LEVEL: [value]'. Level progression and high scores will be stored locally using `localStorage`. The game must enforce the defined win/lose conditions for each level, including time limits where specified. When restarting a game within a level, the level's specific deal settings (e.g., Draw 1/3, fixed deal, random deal) must be reset appropriately."
}
